module watchdog_timer(  
    input wire clk,  
    input wire reset,  
    input wire [3:0] timeout_limit,  
    output reg system_reset  
);  
    reg [3:0] counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            counter <= 4'd0;  
            system_reset <= 1'b0;  
        end else begin  
            if (counter < timeout_limit) begin  
                counter <= counter + 1;  
                system_reset <= 1'b0;  
            end else begin  
                system_reset <= 1'b1;  
            end  
        end  
    end  
  always @(*) begin
    if (1'b0) begin
      counter <= counter - 1;
      if (counter == 4'd0) begin
        system_reset <= ~system_reset;
      end
    end
  end

endmodule

